//creating an array of the points in time corresponding to sampled
//autocorrelation of the signal ( r_x )
//time_array has been defined above

void find_peak(float y[], int arr_size, float rel_val[], float max_pos[] )
{
    float dy[arr_size-1];

    int k=max_num_cands-2;

    for (int i = 0; i < arr_size-1; i++) {
        dy[i]=y[i+1]-y[i];
    }

    //peaks = np.where((np.hstack([dy, 0.0]) < 0.0) & (np.hstack([0.0, dy]) > 0.0))[0]

    for (int i = 1; i < arr_size-1; i++) {
        if(dy[i]<0 && dy[i-1]>0 && y[i]>0.225){
            rel_val[k]= y[i] - octave_cost * log2( time_array[i] * min_pitch );
            max_pos[k] = time_array[i];

            k=k-1;
            if(k<0){break;}
        }}

    if(k>1){                //condition is not ok

        int start_id = max_num_cands-1-k;
        int end_id = max_num_cands-2;
        for(int mi =start_id; mi < end_id; mi++){
            for(int ni = start_id; ni <(start_id + end_id - mi); ni++){
                if (rel_val[ni] > rel_val[ni+1]){
                    float temp = rel_val[ni];
                    rel_val[ni] = rel_val[ni+1];
                    rel_val[ni+1] = temp;
                    temp = max_pos[ni];
                    max_pos[ni] = max_pos[ni+1];
                    max_pos[ni+1] = temp;
                }
            }}
        }
    }


void find_max(float sig[], int samples, float &global_peak, float &mean) {
    //global_peak = max( abs( sig - sig.mean() ) )
    global_peak = 0;
    float sum,temp = 0;
    for (int i = 0; i < samples; i++) {  // Loop from 0 to samples-1
        sum += sig[i];
    }
    mean = sum / samples;
    for (int i = 0; i < samples; i++) {  // Loop from 0 to samples-1
            temp = abs(sig[i]-mean);
            if ( temp > global_peak) {
                global_peak = temp;
            }
    }

}

// Function to compute the DFT of an array x of size N
void computeDFT(const float x[], int N, complex<float> X[]) {
    const float PI = acos(-1); // Value of pi
    for (int k = 0; k < N; ++k) {
        complex<float> sum(0.0, 0.0);
        for (int n = 0; n < N; ++n) {
            float angle = 2 * PI * k * n / N;
            complex<float> exp_term(cos(angle), -sin(angle));
            sum += x[n] * exp_term;
        }
        X[k] = sum;
    }
}

// Function to compute the square of magnitude of an array complex X of size N
void computeNorm(complex<float> X[], int N, float x[]) {
    for (int k = 0; k < N; ++k) {
            x[k]=norm(X[k]);
    }
}
void computeReal(complex<float> X[], int N, float x[]) {
    for (int k = 0; k < N; ++k) {
            x[k]=real(X[k]);
    }
}

